   241→    /**
   242→     * Evaluates client responses via `SaslServer.evaluateResponse` and returns the issued challenge to the client until
   243→     * authentication succeeds or fails.
   244→     *
   245→     * The messages are sent and received as size delimited bytes that consists of a 4 byte network-ordered size N
   246→     * followed by N bytes representing the opaque payload.
   247→     */
   248→    @SuppressWarnings("fallthrough")
   249→    @Override
   250→    public void authenticate() throws IOException {
   251→        if (saslState != SaslState.REAUTH_PROCESS_HANDSHAKE) {
   252→            if (netOutBuffer != null && !flushNetOutBufferAndUpdateInterestOps())
   253→                return;
   254→
   255→            if (saslServer != null && saslServer.isComplete()) {
   256→                setSaslState(SaslState.COMPLETE);
   257→                return;
   258→            }
   259→
   260→            // allocate on heap (as opposed to any socket server memory pool)
   261→            if (netInBuffer == null) netInBuffer = new NetworkReceive(saslAuthRequestMaxReceiveSize, connectionId);
   262→
   263→            try {
   264→                netInBuffer.readFrom(transportLayer);
   265→            } catch (InvalidReceiveException e) {
   266→                throw new SaslAuthenticationException("Failing SASL authentication due to invalid receive size", e);
   267→            }
   268→            if (!netInBuffer.complete())
   269→                return;
   270→            netInBuffer.payload().rewind();
   271→        }
   272→        byte[] clientToken = new byte[netInBuffer.payload().remaining()];
   273→        netInBuffer.payload().get(clientToken, 0, clientToken.length);
   274→        netInBuffer = null; // reset the networkReceive as we read all the data.
   275→        try {
   276→            switch (saslState) {
   277→                case REAUTH_PROCESS_HANDSHAKE:
   278→                case HANDSHAKE_OR_VERSIONS_REQUEST:
   279→                case HANDSHAKE_REQUEST:
   280→                case INITIAL_REQUEST:
   281→                    handleKafkaRequest(clientToken);
   282→                    break;
   283→                case REAUTH_BAD_MECHANISM:
   284→                    throw new SaslAuthenticationException(reauthInfo.badMechanismErrorMessage);
   285→                case AUTHENTICATE:
   286→                    handleSaslToken(clientToken);
   287→                    // When the authentication exchange is complete and no more tokens are expected from the client,
   288→                    // update SASL state. Current SASL state will be updated when outgoing writes to the client complete.
   289→                    if (saslServer.isComplete())
   290→                        setSaslState(SaslState.COMPLETE);
   291→                    break;
   292→                default:
   293→                    break;
   294→            }
   295→        } catch (AuthenticationException e) {
   296→            // Exception will be propagated after response is sent to client
   297→            setSaslState(SaslState.FAILED, e);
   298→        } catch (Exception e) {
   299→            // In the case of IOExceptions and other unexpected exceptions, fail immediately
   300→            saslState = SaslState.FAILED;
   301→            LOG.debug("Failed during {}: {}", reauthInfo.authenticationOrReauthenticationText(), e.getMessage());
   302→            throw e;
   303→        }
   304→    }
