   342→    @Override
   343→    public void reauthenticate(ReauthenticationContext reauthenticationContext) throws IOException {
   344→        NetworkReceive saslHandshakeReceive = reauthenticationContext.networkReceive();
   345→        if (saslHandshakeReceive == null)
   346→            throw new IllegalArgumentException(
   347→                    "Invalid saslHandshakeReceive in server-side re-authentication context: null");
   348→        SaslServerAuthenticator previousSaslServerAuthenticator = (SaslServerAuthenticator) reauthenticationContext.previousAuthenticator();
   349→        reauthInfo.reauthenticating(previousSaslServerAuthenticator.saslMechanism,
   350→                previousSaslServerAuthenticator.principal(), reauthenticationContext.reauthenticationBeginNanos());
   351→        previousSaslServerAuthenticator.close();
   352→        netInBuffer = saslHandshakeReceive;
   353→        LOG.debug("Beginning re-authentication: {}", this);
   354→        netInBuffer.payload().rewind();
   355→        setSaslState(SaslState.REAUTH_PROCESS_HANDSHAKE);
   356→        authenticate();
   357→    }
