   378→    private void setSaslState(SaslState saslState, AuthenticationException exception) {
   379→        if (netOutBuffer != null && !netOutBuffer.completed()) {
   380→            pendingSaslState = saslState;
   381→            pendingException = exception;
   382→        } else {
   383→            this.saslState = saslState;
   384→            LOG.debug("Set SASL server state to {} during {}", saslState, reauthInfo.authenticationOrReauthenticationText());
   385→            this.pendingSaslState = null;
   386→            this.pendingException = null;
   387→            if (exception != null)
   388→                throw exception;
   389→        }
   390→    }
   391→
   392→    private boolean flushNetOutBufferAndUpdateInterestOps() throws IOException {
   393→        boolean flushedCompletely = flushNetOutBuffer();
   394→        if (flushedCompletely) {
   395→            transportLayer.removeInterestOps(SelectionKey.OP_WRITE);
   396→            if (pendingSaslState != null)
   397→                setSaslState(pendingSaslState, pendingException);
   398→        } else
   399→            transportLayer.addInterestOps(SelectionKey.OP_WRITE);
   400→        return flushedCompletely;
   401→    }
   402→
   403→    private boolean flushNetOutBuffer() throws IOException {
   404→        if (!netOutBuffer.completed())
   405→            netOutBuffer.writeTo(transportLayer);
   406→        return netOutBuffer.completed();
   407→    }
