   421→    private void handleSaslToken(byte[] clientToken) throws IOException {
   422→        if (!enableKafkaSaslAuthenticateHeaders) {
   423→            byte[] response = saslServer.evaluateResponse(clientToken);
   424→            if (saslServer.isComplete()) {
   425→                reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
   426→                if (reauthInfo.reauthenticating())
   427→                    reauthInfo.ensurePrincipalUnchanged(principal());
   428→            }
   429→            if (response != null) {
   430→                netOutBuffer = ByteBufferSend.sizePrefixed(ByteBuffer.wrap(response));
   431→                flushNetOutBufferAndUpdateInterestOps();
   432→            }
   433→        } else {
   434→            ByteBuffer requestBuffer = ByteBuffer.wrap(clientToken);
   435→            RequestHeader header = RequestHeader.parse(requestBuffer);
   436→            ApiKeys apiKey = header.apiKey();
   437→            short version = header.apiVersion();
   438→            RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(), Optional.of(clientPort()),
   439→                    KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
   440→            RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
   441→            if (apiKey != ApiKeys.SASL_AUTHENTICATE) {
   442→                IllegalSaslStateException e = new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL authentication.");
   443→                buildResponseOnAuthenticateFailure(requestContext, requestAndSize.request.getErrorResponse(e));
   444→                throw e;
   445→            }
   446→            if (!apiKey.isVersionSupported(version)) {
   447→                // We cannot create an error response if the request version of SaslAuthenticate is not supported
   448→                // This should not normally occur since clients typically check supported versions using ApiVersionsRequest
   449→                throw new UnsupportedVersionException("Version " + version + " is not supported for apiKey " + apiKey);
   450→            }
   451→            /*
   452→             * The client sends multiple SASL_AUTHENTICATE requests, and the client is known
   453→             * to support the required version if any one of them indicates it supports that
   454→             * version.
   455→             */
   456→            if (!reauthInfo.connectedClientSupportsReauthentication)
   457→                reauthInfo.connectedClientSupportsReauthentication = version > 0;
   458→            SaslAuthenticateRequest saslAuthenticateRequest = (SaslAuthenticateRequest) requestAndSize.request;
   459→
   460→            try {
   461→                byte[] responseToken = saslServer.evaluateResponse(
   462→                        Utils.copyArray(saslAuthenticateRequest.data().authBytes()));
   463→                if (reauthInfo.reauthenticating() && saslServer.isComplete())
   464→                    reauthInfo.ensurePrincipalUnchanged(principal());
   465→                // For versions with SASL_AUTHENTICATE header, send a response to SASL_AUTHENTICATE request even if token is empty.
   466→                byte[] responseBytes = responseToken == null ? new byte[0] : responseToken;
   467→                long sessionLifetimeMs = !saslServer.isComplete() ? 0L
   468→                        : reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
   469→                sendKafkaResponse(requestContext, new SaslAuthenticateResponse(
   470→                        new SaslAuthenticateResponseData()
   471→                        .setErrorCode(Errors.NONE.code())
   472→                        .setAuthBytes(responseBytes)
   473→                        .setSessionLifetimeMs(sessionLifetimeMs)));
   474→            } catch (SaslAuthenticationException e) {
   475→                buildResponseOnAuthenticateFailure(requestContext,
   476→                        new SaslAuthenticateResponse(
   477→                                new SaslAuthenticateResponseData()
   478→                                .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
   479→                                .setErrorMessage(e.getMessage())));
   480→                throw e;
   481→            } catch (SaslException e) {
   482→                KerberosError kerberosError = KerberosError.fromException(e);
   483→                if (kerberosError != null && kerberosError.retriable()) {
   484→                    // Handle retriable Kerberos exceptions as I/O exceptions rather than authentication exceptions
   485→                    throw e;
   486→                } else {
   487→                    // DO NOT include error message from the `SaslException` in the client response since it may
   488→                    // contain sensitive data like the existence of the user.
   489→                    String errorMessage = "Authentication failed during "
   490→                            + reauthInfo.authenticationOrReauthenticationText()
   491→                            + " due to invalid credentials with SASL mechanism " + saslMechanism;
   492→                    buildResponseOnAuthenticateFailure(requestContext, new SaslAuthenticateResponse(
   493→                            new SaslAuthenticateResponseData()
   494→                            .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
   495→                            .setErrorMessage(errorMessage)));
   496→                    throw new SaslAuthenticationException(errorMessage, e);
   497→                }
   498→            }
   499→        }
   500→    }
   501→
   502→    /**
   503→     * @throws InvalidRequestException if the request is not in Kafka format or if the API key is invalid. Clients
   504→     * that support SASL without support for KIP-43 (e.g. Kafka Clients 0.9.x) are in the former bucket - the first
   505→     * packet such clients send is a GSSAPI token starting with 0x60.
   506→     */
   507→    private void handleKafkaRequest(byte[] requestBytes) throws IOException, AuthenticationException {
   508→        try {
   509→            ByteBuffer requestBuffer = ByteBuffer.wrap(requestBytes);
   510→            RequestHeader header = RequestHeader.parse(requestBuffer);
   511→            ApiKeys apiKey = header.apiKey();
   512→
   513→            // Raise an error prior to parsing if the api cannot be handled at this layer. This avoids
   514→            // unnecessary exposure to some of the more complex schema types.
   515→            if (apiKey != ApiKeys.API_VERSIONS && apiKey != ApiKeys.SASL_HANDSHAKE)
   516→                throw new InvalidRequestException("Unexpected Kafka request of type " + apiKey + " during SASL handshake.");
   517→
   518→            LOG.debug("Handling Kafka request {} during {}", apiKey, reauthInfo.authenticationOrReauthenticationText());
   519→
   520→            RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(), Optional.of(clientPort()),
   521→                    KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
   522→            RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
   523→
   524→            // A valid Kafka request was received, we can now update the sasl state
   525→            if (saslState == SaslState.INITIAL_REQUEST)
   526→                setSaslState(SaslState.HANDSHAKE_OR_VERSIONS_REQUEST);
   527→
   528→            if (apiKey == ApiKeys.API_VERSIONS)
   529→                handleApiVersionsRequest(requestContext, (ApiVersionsRequest) requestAndSize.request);
   530→            else {
   531→                String clientMechanism = handleHandshakeRequest(requestContext, (SaslHandshakeRequest) requestAndSize.request);
   532→                if (!reauthInfo.reauthenticating() || reauthInfo.saslMechanismUnchanged(clientMechanism)) {
   533→                    createSaslServer(clientMechanism);
   534→                    setSaslState(SaslState.AUTHENTICATE);
   535→                }
   536→            }
   537→        } catch (InvalidRequestException e) {
   538→            if (saslState == SaslState.INITIAL_REQUEST) {
   539→                // InvalidRequestException is thrown if the request is not in Kafka format or if the API key is invalid.
   540→                // If it's the initial request, this could be an ancient client (see method documentation for more details),
   541→                // a client configured with the wrong security protocol or a non kafka-client altogether (eg http client).
   542→                throw new InvalidRequestException("Invalid request, potential reasons: kafka client configured with the " +
   543→                    "wrong security protocol, it does not support KIP-43 or it is not a kafka client.", e);
   544→            }
   545→            throw e;
   546→        }
   547→    }
   548→
   549→    private String handleHandshakeRequest(RequestContext context, SaslHandshakeRequest handshakeRequest) throws IOException, UnsupportedSaslMechanismException {
   550→        String clientMechanism = handshakeRequest.data().mechanism();
   551→        short version = context.header.apiVersion();
   552→        if (version >= 1)
   553→            this.enableKafkaSaslAuthenticateHeaders(true);
   554→        if (enabledMechanisms.contains(clientMechanism)) {
   555→            LOG.debug("Using SASL mechanism '{}' provided by client", clientMechanism);
   556→            sendKafkaResponse(context, new SaslHandshakeResponse(
   557→                    new SaslHandshakeResponseData().setErrorCode(Errors.NONE.code()).setMechanisms(enabledMechanisms)));
   558→            return clientMechanism;
   559→        } else {
   560→            LOG.debug("SASL mechanism '{}' requested by client is not supported", clientMechanism);
   561→            buildResponseOnAuthenticateFailure(context, new SaslHandshakeResponse(
   562→                    new SaslHandshakeResponseData().setErrorCode(Errors.UNSUPPORTED_SASL_MECHANISM.code()).setMechanisms(enabledMechanisms)));
   563→            throw new UnsupportedSaslMechanismException("Unsupported SASL mechanism " + clientMechanism);
   564→        }
   565→    }
   566→
   567→    // Visible to override for testing
   568→    protected void enableKafkaSaslAuthenticateHeaders(boolean flag) {
   569→        this.enableKafkaSaslAuthenticateHeaders = flag;
   570→    }
   571→
   572→    private void handleApiVersionsRequest(RequestContext context, ApiVersionsRequest apiVersionsRequest) throws IOException {
   573→        if (saslState != SaslState.HANDSHAKE_OR_VERSIONS_REQUEST)
   574→            throw new IllegalStateException("Unexpected ApiVersions request received during SASL authentication state " + saslState);
   575→
   576→        if (apiVersionsRequest.hasUnsupportedRequestVersion())
   577→            sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.UNSUPPORTED_VERSION.exception()));
   578→        else if (!apiVersionsRequest.isValid())
   579→            sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.INVALID_REQUEST.exception()));
   580→        else {
   581→            metadataRegistry.registerClientInformation(new ClientInformation(apiVersionsRequest.data().clientSoftwareName(),
   582→                apiVersionsRequest.data().clientSoftwareVersion()));
   583→            sendKafkaResponse(context, apiVersionSupplier.apply(apiVersionsRequest.version()));
   584→            setSaslState(SaslState.HANDSHAKE_REQUEST);
   585→        }
   586→    }
   587→
   588→    /**
   589→     * Build a {@link Send} response on {@link #authenticate()} failure. The actual response is sent out when
   590→     * {@link #sendAuthenticationFailureResponse()} is called.
   591→     */
   592→    private void buildResponseOnAuthenticateFailure(RequestContext context, AbstractResponse response) {
   593→        authenticationFailureSend = context.buildResponseSend(response);
   594→    }
   595→
   596→    /**
   597→     * Send any authentication failure response that may have been previously built.
   598→     */
   599→    private void sendAuthenticationFailureResponse() throws IOException {
   600→        if (authenticationFailureSend == null)
   601→            return;
   602→        sendKafkaResponse(authenticationFailureSend);
   603→        authenticationFailureSend = null;
   604→    }
   605→
   606→    private void sendKafkaResponse(RequestContext context, AbstractResponse response) throws IOException {
   607→        sendKafkaResponse(context.buildResponseSend(response));
   608→    }
   609→
   610→    private void sendKafkaResponse(Send send) throws IOException {
   611→        netOutBuffer = send;
   612→        flushNetOutBufferAndUpdateInterestOps();
   613→    }
   614→
   615→    /**
   616→     * Information related to re-authentication
   617→     */
   618→    private class ReauthInfo {
   619→        public String previousSaslMechanism;
   620→        public KafkaPrincipal previousKafkaPrincipal;
   621→        public long reauthenticationBeginNanos;
   622→        public Long sessionExpirationTimeNanos;
   623→        public boolean connectedClientSupportsReauthentication;
   624→        public long authenticationEndNanos;
   625→        public String badMechanismErrorMessage;
   626→
   627→        public void reauthenticating(String previousSaslMechanism, KafkaPrincipal previousKafkaPrincipal,
   628→                long reauthenticationBeginNanos) {
   629→            this.previousSaslMechanism = Objects.requireNonNull(previousSaslMechanism);
   630→            this.previousKafkaPrincipal = Objects.requireNonNull(previousKafkaPrincipal);
   631→            this.reauthenticationBeginNanos = reauthenticationBeginNanos;
   632→        }
   633→
   634→        public boolean reauthenticating() {
   635→            return previousSaslMechanism != null;
   636→        }
   637→
   638→        public String authenticationOrReauthenticationText() {
   639→            return reauthenticating() ? "re-authentication" : "authentication";
   640→        }
   641→
   642→        public void ensurePrincipalUnchanged(KafkaPrincipal reauthenticatedKafkaPrincipal) throws SaslAuthenticationException {
   643→            if (!previousKafkaPrincipal.equals(reauthenticatedKafkaPrincipal)) {
   644→                throw new SaslAuthenticationException(String.format(
   645→                        "Cannot change principals during re-authentication from %s.%s: %s.%s",
   646→                        previousKafkaPrincipal.getPrincipalType(), previousKafkaPrincipal.getName(),
   647→                        reauthenticatedKafkaPrincipal.getPrincipalType(), reauthenticatedKafkaPrincipal.getName()));
   648→            }
   649→        }
   650→
   651→        /*
   652→         * We define the REAUTH_BAD_MECHANISM state because the failed re-authentication
   653→         * metric does not get updated if we send back an error immediately upon the
   654→         * start of re-authentication.
   655→         */
   656→        public boolean saslMechanismUnchanged(String clientMechanism) {
   657→            if (previousSaslMechanism.equals(clientMechanism))
   658→                return true;
   659→            badMechanismErrorMessage = String.format(
   660→                    "SASL mechanism '%s' requested by client is not supported for re-authentication of mechanism '%s'",
   661→                    clientMechanism, previousSaslMechanism);
   662→            LOG.debug(badMechanismErrorMessage);
   663→            setSaslState(SaslState.REAUTH_BAD_MECHANISM);
   664→            return false;
   665→        }
   666→
   667→        private long calcCompletionTimesAndReturnSessionLifetimeMs() {
   668→            long retvalSessionLifetimeMs = 0L;
   669→            long authenticationEndMs = time.milliseconds();
   670→            authenticationEndNanos = time.nanoseconds();
   671→            Long credentialExpirationMs = (Long) saslServer
   672→                    .getNegotiatedProperty(SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY);
   673→            Long connectionsMaxReauthMs = connectionsMaxReauthMsByMechanism.get(saslMechanism);
   674→            boolean maxReauthSet = connectionsMaxReauthMs != null && connectionsMaxReauthMs > 0;
   675→
   676→            if (credentialExpirationMs != null || maxReauthSet) {
   677→                if (credentialExpirationMs == null)
   678→                    retvalSessionLifetimeMs = zeroIfNegative(connectionsMaxReauthMs);
   679→                else if (!maxReauthSet)
   680→                    retvalSessionLifetimeMs = zeroIfNegative(credentialExpirationMs - authenticationEndMs);
   681→                else
   682→                    retvalSessionLifetimeMs = zeroIfNegative(Math.min(credentialExpirationMs - authenticationEndMs, connectionsMaxReauthMs));
   683→
   684→                sessionExpirationTimeNanos = authenticationEndNanos + 1000 * 1000 * retvalSessionLifetimeMs;
   685→            }
   686→
   687→            if (credentialExpirationMs != null) {
   688→                LOG.debug(
   689→                        "Authentication complete; session max lifetime from broker config={} ms, credential expiration={} ({} ms); session expiration = {} ({} ms), sending {} ms to client",
   690→                        connectionsMaxReauthMs, new Date(credentialExpirationMs),
   691→                        credentialExpirationMs - authenticationEndMs,
   692→                        new Date(authenticationEndMs + retvalSessionLifetimeMs), retvalSessionLifetimeMs,
   693→                        retvalSessionLifetimeMs);
   694→            } else {
   695→                if (sessionExpirationTimeNanos != null)
   696→                    LOG.debug(
   697→                            "Authentication complete; session max lifetime from broker config={} ms, no credential expiration; session expiration = {} ({} ms), sending {} ms to client",
   698→                            connectionsMaxReauthMs, new Date(authenticationEndMs + retvalSessionLifetimeMs),
   699→                            retvalSessionLifetimeMs, retvalSessionLifetimeMs);
   700→                else
   701→                    LOG.debug(
   702→                            "Authentication complete; session max lifetime from broker config={} ms, no credential expiration; no session expiration, sending 0 ms to client",
   703→                            connectionsMaxReauthMs);
   704→            }
   705→            return retvalSessionLifetimeMs;
   706→        }
   707→
   708→        public Long reauthenticationLatencyMs() {
   709→            if (!reauthenticating())
   710→                return null;
   711→            // record at least 1 ms if there is some latency
   712→            long latencyNanos = authenticationEndNanos - reauthenticationBeginNanos;
   713→            return latencyNanos == 0L ? 0L : Math.max(1L, Math.round(latencyNanos / 1000.0 / 1000.0));
   714→        }
   715→
   716→        private long zeroIfNegative(long value) {
   717→            return Math.max(0L, value);
   718→        }        
   719→    }
   720→}
   721→

