   421→    private void handleSaslToken(byte[] clientToken) throws IOException {
   422→        if (!enableKafkaSaslAuthenticateHeaders) {
   423→            byte[] response = saslServer.evaluateResponse(clientToken);
   424→            if (saslServer.isComplete()) {
   425→                reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
   426→                if (reauthInfo.reauthenticating())
   427→                    reauthInfo.ensurePrincipalUnchanged(principal());
   428→            }
   429→            if (response != null) {
   430→                netOutBuffer = ByteBufferSend.sizePrefixed(ByteBuffer.wrap(response));
   431→                flushNetOutBufferAndUpdateInterestOps();
   432→            }
   433→        } else {
   434→            ByteBuffer requestBuffer = ByteBuffer.wrap(clientToken);
   435→            RequestHeader header = RequestHeader.parse(requestBuffer);
   436→            ApiKeys apiKey = header.apiKey();
   437→            short version = header.apiVersion();
   438→            RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(), Optional.of(clientPort()),
   439→                    KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
   440→            RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
   441→            if (apiKey != ApiKeys.SASL_AUTHENTICATE) {
   442→                IllegalSaslStateException e = new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL authentication.");
   443→                buildResponseOnAuthenticateFailure(requestContext, requestAndSize.request.getErrorResponse(e));
   444→                throw e;
   445→            }
   446→            if (!apiKey.isVersionSupported(version)) {
   447→                // We cannot create an error response if the request version of SaslAuthenticate is not supported
   448→                // This should not normally occur since clients typically check supported versions using ApiVersionsRequest
   449→                throw new UnsupportedVersionException("Version " + version + " is not supported for apiKey " + apiKey);
   450→            }
   451→            /*
   452→             * The client sends multiple SASL_AUTHENTICATE requests, and the client is known
   453→             * to support the required version if any one of them indicates it supports that
   454→             * version.
   455→             */
   456→            if (!reauthInfo.connectedClientSupportsReauthentication)
   457→                reauthInfo.connectedClientSupportsReauthentication = version > 0;
   458→            SaslAuthenticateRequest saslAuthenticateRequest = (SaslAuthenticateRequest) requestAndSize.request;
   459→
   460→            try {
   461→                byte[] responseToken = saslServer.evaluateResponse(
   462→                        Utils.copyArray(saslAuthenticateRequest.data().authBytes()));
   463→                if (reauthInfo.reauthenticating() && saslServer.isComplete())
   464→                    reauthInfo.ensurePrincipalUnchanged(principal());
   465→                // For versions with SASL_AUTHENTICATE header, send a response to SASL_AUTHENTICATE request even if token is empty.
   466→                byte[] responseBytes = responseToken == null ? new byte[0] : responseToken;
   467→                long sessionLifetimeMs = !saslServer.isComplete() ? 0L
   468→                        : reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
   469→                sendKafkaResponse(requestContext, new SaslAuthenticateResponse(
   470→                        new SaslAuthenticateResponseData()
   471→                        .setErrorCode(Errors.NONE.code())
   472→                        .setAuthBytes(responseBytes)
   473→                        .setSessionLifetimeMs(sessionLifetimeMs)));
   474→            } catch (SaslAuthenticationException e) {
   475→                buildResponseOnAuthenticateFailure(requestContext,
   476→                        new SaslAuthenticateResponse(
   477→                                new SaslAuthenticateResponseData()
   478→                                .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
   479→                                .setErrorMessage(e.getMessage())));
   480→                throw e;
   481→            } catch (SaslException e) {
   482→                KerberosError kerberosError = KerberosError.fromException(e);
   483→                if (kerberosError != null && kerberosError.retriable()) {
   484→                    // Handle retriable Kerberos exceptions as I/O exceptions rather than authentication exceptions
   485→                    throw e;
   486→                } else {
   487→                    // DO NOT include error message from the `SaslException` in the client response since it may
   488→                    // contain sensitive data like the existence of the user.
   489→                    String errorMessage = "Authentication failed during "
   490→                            + reauthInfo.authenticationOrReauthenticationText()
   491→                            + " due to invalid credentials with SASL mechanism " + saslMechanism;
   492→                    buildResponseOnAuthenticateFailure(requestContext, new SaslAuthenticateResponse(
   493→                            new SaslAuthenticateResponseData()
   494→                            .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
   495→                            .setErrorMessage(errorMessage)));
   496→                    throw new SaslAuthenticationException(errorMessage, e);
   497→                }
   498→            }
   499→        }
   500→    }
