   588→    /**
   589→     * Build a {@link Send} response on {@link #authenticate()} failure. The actual response is sent out when
   590→     * {@link #sendAuthenticationFailureResponse()} is called.
   591→     */
   592→    private void buildResponseOnAuthenticateFailure(RequestContext context, AbstractResponse response) {
   593→        authenticationFailureSend = context.buildResponseSend(response);
   594→    }
