   596→    /**
   597→     * Send any authentication failure response that may have been previously built.
   598→     */
   599→    private void sendAuthenticationFailureResponse() throws IOException {
   600→        if (authenticationFailureSend == null)
   601→            return;
   602→        sendKafkaResponse(authenticationFailureSend);
   603→        authenticationFailureSend = null;
   604→    }
   605→
   606→    private void sendKafkaResponse(RequestContext context, AbstractResponse response) throws IOException {
   607→        sendKafkaResponse(context.buildResponseSend(response));
   608→    }
